var parts = msg.topic.split('/');
var shirtId = parts[2];
var messageType = parts[3];

var payload;
if (typeof msg.payload === 'string') {
    try {
        payload = JSON.parse(msg.payload);
    } catch(e) {
        node.error('Failed to parse JSON: ' + e.message);
        return null;
    }
} else {
    payload = msg.payload;
}

if (!payload) return null;

var points = [];
var baseTime = Date.now();

if (messageType === 'ECG') {
    // 1. High frequency biometric wave
    points.push({
        measurement: 'biometric_waves',
        tags: { shirt_id: shirtId, data_type: 'ECG' },
        fields: {
            samples: JSON.stringify(payload.samples || []),
            frequency: payload.frequency || 128,
            sampling_frequency: payload.frequency || 128,
            samplenum: payload.samplenum || 0
        },
        timestamp: baseTime
    });
    // 2. Low frequency vitals summary
    if (payload.heartrate !== undefined) {
        points.push({
            measurement: 'vitals_summary',
            tags: { shirt_id: shirtId, data_type: 'ECG' },
            fields: { heartrate: payload.heartrate },
            timestamp: baseTime
        });
    }

} else if (messageType === 'ACC_GYRO') {
    // 1. High frequency biometric wave
    points.push({
        measurement: 'biometric_waves',
        tags: { shirt_id: shirtId, data_type: 'ACC_GYRO' },
        fields: {
            samples: JSON.stringify(payload.samples || []),
            frequency: payload.sampling_frequency || 3,
            sampling_frequency: payload.sampling_frequency || 3,
            samplenum: payload.samplenum || 0
        },
        timestamp: baseTime
    });
    // 2. Low frequency vitals summary
    if (payload.orientation !== undefined) {
        points.push({
            measurement: 'vitals_summary',
            tags: { shirt_id: shirtId, data_type: 'ACC_GYRO' },
            fields: { orientation: payload.orientation },
            timestamp: baseTime
        });
    }

} else if (messageType === 'STRAINGAUGES_MIXED') {
    // 1. High frequency biometric wave
    var freq = 1000 / (payload.sample_period_press || 75);
    points.push({
        measurement: 'biometric_waves',
        tags: { shirt_id: shirtId, data_type: 'STRAINGAUGES_MIXED' },
        fields: {
            samples: JSON.stringify(payload.samples_1 || []),
            frequency: freq,
            sampling_frequency: freq,
            samplenum: payload.samplenum || 0
        },
        timestamp: baseTime
    });
    // 2. Low frequency vitals summary
    if (payload.breathrate !== undefined) {
        points.push({
            measurement: 'vitals_summary',
            tags: { shirt_id: shirtId, data_type: 'STRAINGAUGES_MIXED' },
            fields: { breathrate: payload.breathrate },
            timestamp: baseTime
        });
    }

} else if (messageType === 'BABY_ORIENTATION') {
    points.push({
        measurement: 'vitals_summary',
        tags: { shirt_id: shirtId, data_type: 'BABY_ORIENTATION' },
        fields: { orientation: payload.orientation || 0 },
        timestamp: baseTime
    });

} else if (messageType === 'TemperatureNTC' || messageType === 'TEMPERATURE') {
    var tempVal = NaN;
    if (typeof payload === 'number') {
        tempVal = payload;
    } else if (typeof payload === 'string') {
        tempVal = parseFloat(payload);
    } else if (payload && typeof payload === 'object') {
        var val = payload.temperature !== undefined ? payload.temperature : payload.value;
        if (val !== undefined) {
            tempVal = parseFloat(val);
        }
    }

    // Salva il dato in InfluxDB solo se è valido (maggiore di 0 e minore o uguale a 60)
    if (!isNaN(tempVal) && tempVal > 0 && tempVal <= 60) {
        points.push({
            measurement: 'vitals_summary',
            tags: { shirt_id: shirtId, data_type: 'TEMPERATURE' }, // Mantengo 'TEMPERATURE' per InfluxDB/Grafana
            fields: { temperature: tempVal },
            timestamp: baseTime
        });
    }

} else if (messageType === 'R2R') {
    if (payload.heartrate !== undefined) {
        points.push({
            measurement: 'vitals_summary',
            tags: { shirt_id: shirtId, data_type: 'R2R' },
            fields: { heartrate: payload.heartrate },
            timestamp: baseTime
        });
    }

} else if (messageType === 'BREATH_ANNOTATION') {
    if (payload.breathrate !== undefined) {
        points.push({
            measurement: 'vitals_summary',
            tags: { shirt_id: shirtId, data_type: 'BREATH_ANNOTATION' },
            fields: { breathrate: payload.breathrate },
            timestamp: baseTime
        });
    }

} else if (messageType === 'BATTERY_INFO') {
    points.push({
        measurement: 'device_diagnostics',
        tags: { shirt_id: shirtId, data_type: 'BATTERY_INFO' },
        fields: {
            state_of_charge: payload.state_of_charge !== undefined ? payload.state_of_charge : 0,
            voltage: payload.voltage || 0,
            charging: payload.charging !== undefined ? payload.charging : 0
        },
        timestamp: baseTime
    });

} else if (messageType === 'FLASH_INFO') {
    points.push({
        measurement: 'device_diagnostics',
        tags: { shirt_id: shirtId, data_type: 'FLASH_INFO' },
        fields: {
            flash_pointer: payload.pointer || 0,
            flash_status: payload.status || 0
        },
        timestamp: baseTime
    });

} else if (messageType === 'SYSTEM_INFO') {
    points.push({
        measurement: 'device_diagnostics',
        tags: { shirt_id: shirtId, data_type: 'SYSTEM_INFO' },
        fields: {
            system_demo: payload.demo || 0,
            system_pressure: payload.pressure || 0,
            system_ecg: payload.ecg || 0,
            system_orientation: payload.orientation || 0,
            system_ecg_frequency: payload.ecg_frequency || 0,
            system_accelerometer: payload.accelerometer || 0,
            system_led_mode: payload.led_mode || 0,
            system_temperature: payload.temperature || 0,
            system_r2r: payload.r2r || 0,
            system_sampleperiod: payload.sampleperiod || 0,
            system_battery: payload.battery || 0,
            system_mems_mode: payload.mems_mode || 0,
            system_bio: payload.bio || 0
        },
        timestamp: baseTime
    });

} else if (messageType === 'FIRMWARE_VERSION') {
    points.push({
        measurement: 'device_diagnostics',
        tags: { shirt_id: shirtId, data_type: 'FIRMWARE_VERSION' },
        fields: {
            fw_major: payload.major || 0,
            fw_minor: payload.minor || 0,
            fw_revision: payload.revision || 0,
            fw_bootloader_major: payload.bootloader_major || 0,
            fw_bootloader_minor: payload.bootloader_minor || 0,
            fw_bootloader_revision: payload.bootloader_revision || 0,
            fw_hardware: payload.hardware || 0
        },
        timestamp: baseTime
    });
}

if (points.length > 0) {
    msg.payload = points;
    return msg;
}
return null;
